1	import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
2	import {
3	  combineHeaders,
4	  convertImageModelFileToDataUri,
5	  createBinaryResponseHandler,
6	  createJsonResponseHandler,
7	  createStatusCodeErrorResponseHandler,
8	  delay,
9	  FetchFunction,
10	  getFromApi,
11	  postJsonToApi,
12	} from '@ai-sdk/provider-utils';
13	import {
14	  asyncPollResponseSchema,
15	  asyncSubmitResponseSchema,
16	} from './fireworks-image-api';
17	import { FireworksImageModelId } from './fireworks-image-options';
18	
19	const DEFAULT_POLL_INTERVAL_MILLIS = 500;
20	const DEFAULT_POLL_TIMEOUT_MILLIS = 120000; // 2 minutes for image generation
21	
22	interface FireworksImageModelBackendConfig {
23	  urlFormat: 'workflows' | 'workflows_async' | 'image_generation';
24	  supportsSize?: boolean;
25	  supportsEditing?: boolean;
26	}
27	
28	const modelToBackendConfig: Partial<
29	  Record<FireworksImageModelId, FireworksImageModelBackendConfig>
30	> = {
31	  'accounts/fireworks/models/flux-1-dev-fp8': {
32	    urlFormat: 'workflows',
33	  },
34	  'accounts/fireworks/models/flux-1-schnell-fp8': {
35	    urlFormat: 'workflows',
36	  },
37	  'accounts/fireworks/models/flux-kontext-pro': {
38	    urlFormat: 'workflows_async',
39	    supportsEditing: true,
40	  },
41	  'accounts/fireworks/models/flux-kontext-max': {
42	    urlFormat: 'workflows_async',
43	    supportsEditing: true,
44	  },
45	  'accounts/fireworks/models/playground-v2-5-1024px-aesthetic': {
46	    urlFormat: 'image_generation',
47	    supportsSize: true,
48	  },
49	  'accounts/fireworks/models/japanese-stable-diffusion-xl': {
50	    urlFormat: 'image_generation',
51	    supportsSize: true,
52	  },
53	  'accounts/fireworks/models/playground-v2-1024px-aesthetic': {
54	    urlFormat: 'image_generation',
55	    supportsSize: true,
56	  },
57	  'accounts/fireworks/models/stable-diffusion-xl-1024-v1-0': {
58	    urlFormat: 'image_generation',
59	    supportsSize: true,
60	  },
61	  'accounts/fireworks/models/SSD-1B': {
62	    urlFormat: 'image_generation',
63	    supportsSize: true,
64	  },
65	};
66	
67	function getUrlForModel(
68	  baseUrl: string,
69	  modelId: FireworksImageModelId,
70	): string {
71	  const config = modelToBackendConfig[modelId];
72	
73	  switch (config?.urlFormat) {
74	    case 'image_generation':
75	      return `${baseUrl}/image_generation/${modelId}`;
76	    case 'workflows_async':
77	      return `${baseUrl}/workflows/${modelId}`;
78	    case 'workflows':
79	    default:
80	      return `${baseUrl}/workflows/${modelId}/text_to_image`;
81	  }
82	}
83	
84	function getPollUrlForModel(
85	  baseUrl: string,
86	  modelId: FireworksImageModelId,
87	): string {
88	  return `${baseUrl}/workflows/${modelId}/get_result`;
89	}
90	
91	interface FireworksImageModelConfig {
92	  provider: string;
93	  baseURL: string;
94	  headers: () => Record<string, string>;
95	  fetch?: FetchFunction;
96	  /**
97	   * Poll interval in milliseconds between status checks for async models.
98	   * Defaults to 500ms.
99	   */
100	  pollIntervalMillis?: number;
101	  /**
102	   * Overall timeout in milliseconds for polling before giving up.
103	   * Defaults to 120000ms (2 minutes).
104	   */
105	  pollTimeoutMillis?: number;
106	  _internal?: {
107	    currentDate?: () => Date;
108	  };
109	}
110	
111	export class FireworksImageModel implements ImageModelV3 {
112	  readonly specificationVersion = 'v3';
113	  readonly maxImagesPerCall = 1;
114	
115	  get provider(): string {
116	    return this.config.provider;
117	  }
118	
119	  constructor(
120	    readonly modelId: FireworksImageModelId,
121	    private config: FireworksImageModelConfig,
122	  ) {}
123	
124	  async doGenerate({
125	    prompt,
126	    n,
127	    size,
128	    aspectRatio,
129	    seed,
130	    providerOptions,
131	    headers,
132	    abortSignal,
133	    files,
134	    mask,
135	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
136	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
137	  > {
138	    const warnings: Array<SharedV3Warning> = [];
139	
140	    const backendConfig = modelToBackendConfig[this.modelId];
141	    if (!backendConfig?.supportsSize && size != null) {
142	      warnings.push({
143	        type: 'unsupported',
144	        feature: 'size',
145	        details:
146	          'This model does not support the `size` option. Use `aspectRatio` instead.',
147	      });
148	    }
149	
150	    // Use supportsSize as a proxy for whether the model does not support
151	    // aspectRatio. This invariant holds for the current set of models.
152	    if (backendConfig?.supportsSize && aspectRatio != null) {
153	      warnings.push({
154	        type: 'unsupported',
155	        feature: 'aspectRatio',
156	        details: 'This model does not support the `aspectRatio` option.',
157	      });
158	    }
159	
160	    // Handle files for image editing
161	    const hasInputImage = files != null && files.length > 0;
162	    let inputImage: string | undefined;
163	
164	    if (hasInputImage) {
165	      inputImage = convertImageModelFileToDataUri(files[0]);
166	
167	      if (files.length > 1) {
168	        warnings.push({
169	          type: 'other',
170	          message:
171	            'Fireworks only supports a single input image. Additional images are ignored.',
172	        });
173	      }
174	    }
175	
176	    // Warn about mask - Fireworks Kontext models don't support explicit masks
177	    if (mask != null) {
178	      warnings.push({
179	        type: 'unsupported',
180	        feature: 'mask',
181	        details:
182	          'Fireworks Kontext models do not support explicit masks. Use the prompt to describe the areas to edit.',
183	      });
184	    }
185	
186	    const splitSize = size?.split('x');
187	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
188	    const combinedHeaders = combineHeaders(this.config.headers(), headers);
189	
190	    const body = {
191	      prompt,
192	      aspect_ratio: aspectRatio,
193	      seed,
194	      samples: n,
195	      ...(inputImage && { input_image: inputImage }),
196	      ...(splitSize && { width: splitSize[0], height: splitSize[1] }),
197	      ...(providerOptions.fireworks ?? {}),
198	    };
199	
200	    // Handle async models that require polling (e.g., flux-kontext-*)
201	    if (backendConfig?.urlFormat === 'workflows_async') {
202	      return this.doGenerateAsync({
203	        body,
204	        headers: combinedHeaders,
205	        abortSignal,
206	        warnings,
207	        currentDate,
208	      });
209	    }
210	
211	    // Handle sync models that return binary directly
212	    const { value: response, responseHeaders } = await postJsonToApi({
213	      url: getUrlForModel(this.config.baseURL, this.modelId),
214	      headers: combinedHeaders,
215	      body,
216	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
217	      successfulResponseHandler: createBinaryResponseHandler(),
218	      abortSignal,
219	      fetch: this.config.fetch,
220	    });
221	
222	    return {
223	      images: [response],
224	      warnings,
225	      response: {
226	        timestamp: currentDate,
227	        modelId: this.modelId,
228	        headers: responseHeaders,
229	      },
230	    };
231	  }
232	
233	  /**
234	   * Handles async image generation for models like flux-kontext-* that return
235	   * a request_id and require polling for results.
236	   */
237	  private async doGenerateAsync({
238	    body,
239	    headers,
240	    abortSignal,
241	    warnings,
242	    currentDate,
243	  }: {
244	    body: Record<string, unknown>;
245	    headers: Record<string, string | undefined>;
246	    abortSignal: AbortSignal | undefined;
247	    warnings: Array<SharedV3Warning>;
248	    currentDate: Date;
249	  }): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
250	    // Submit the generation request
251	    const { value: submitResponse } = await postJsonToApi({
252	      url: getUrlForModel(this.config.baseURL, this.modelId),
253	      headers,
254	      body,
255	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
256	      successfulResponseHandler: createJsonResponseHandler(
