import { createJsonErrorResponseHandler } from '@ai-sdk/provider-utils';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export interface PixelArtModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export const pixelartImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  created: z.number().nullish(),
});

const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      type: z.string().nullish(),
      code: z.string().nullish(),
    })
    .nullish(),
});

export const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => {
    const parsed = pixelartErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    return parsed.data.error?.message ?? 'Unknown PixelArt error';
  },
});

