import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import type { FetchFunction } from '@ai-sdk/provider-utils';

const prompt = 'A cute pixel art cat';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ 'api-key': 'test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const testDate = new Date('2024-01-01T00:00:00Z');
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: {
        type: 'json-value',
        body: {
          data: [{ b64_json: 'test-image-base64-data' }],
          created: 1234567890,
        },
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });

    it('should return default maxImagesPerCall for unknown models', () => {
      const model = new PixelArtImageModel('custom-model', {
        provider: 'pixelart.image',
        baseURL: 'https://api.example.com',
        headers: () => ({ 'api-key': 'test-key' }),
      });

      expect(model.maxImagesPerCall).toBe(1);
    });
  });

  describe('doGenerate', () => {
    it('should pass the correct parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {
          pixelart: { style: 'pixel', pixelDensity: 2 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
        style: 'pixel',
        pixel_density: 2,
      });
    });

    it('should call the correct url', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestMethod).toStrictEqual('POST');
      expect(server.calls[0].requestUrl).toStrictEqual(
        'https://api.example.com/images/generations',
      );
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          'Custom-Provider-Header': 'provider-header-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should return images from response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toStrictEqual(['test-image-base64-data']);
    });

    it('should warn when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toStrictEqual([
        {
          type: 'unsupported',
          feature: 'aspectRatio',
          details:
            'PixelArt does not support aspect ratio. Use `size` instead.',
        },
      ]);
    });

    it('should send minimal body when optional params are omitted', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
      });
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt',
            type: 'invalid_request_error',
          },
        }),
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toThrow('Invalid prompt');
    });

    it('should respect the abort signal', async () => {
      const model = createBasicModel();
      const controller = new AbortController();

      const generatePromise = model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        abortSignal: controller.signal,
      });

      controller.abort();

      await expect(generatePromise).rejects.toThrow(
        'This operation was aborted',
      );
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart-standard',
          headers: expect.any(Object),
        });
      });

      it('should include response headers from API call', async () => {
        server.urls[
          'https://api.example.com/images/generations'
        ].response = {
          type: 'json-value',
          headers: {
            'x-request-id': 'test-request-id',
          },
          body: {
            data: [{ b64_json: 'test-image-base64-data' }],
            created: 1234567890,
          },
        };

        const model = createBasicModel();
        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.response.headers).toStrictEqual({
          'content-length': '56',
          'x-request-id': 'test-request-id',
          'content-type': 'application/json',
        });
      });
    });

    describe('provider options', () => {
      it('should pass style option', async () => {
        const model = createBasicModel();

        await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {
            pixelart: { style: 'retro' },
          },
        });

        expect(await server.calls[0].requestBodyJson).toStrictEqual({
          model: 'pixelart-standard',
          prompt,
          n: 1,
          style: 'retro',
        });
      });

      it('should pass pixelDensity option', async () => {
        const model = createBasicModel();

        await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {
            pixelart: { pixelDensity: 3 },
          },
        });

        expect(await server.calls[0].requestBodyJson).toStrictEqual({
          model: 'pixelart-standard',
          prompt,
          n: 1,
          pixel_density: 3,
        });
      });

      it('should pass 8bit style option', async () => {
        const model = createBasicModel();

        await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {
            pixelart: { style: '8bit' },
          },
        });

        expect(await server.calls[0].requestBodyJson).toStrictEqual({
          model: 'pixelart-standard',
          prompt,
          n: 1,
          style: '8bit',
        });
      });
    });
  });
});

